dtsPropsFor.Button:
/** Visual style — defaults to "primary". */
variant?: "primary" | "goldCta" | "secondary" | "ghost" | "outlineLight" | "solidLight";
/** Size — defaults to "md". */
size?: "sm" | "md" | "lg";
/** When set, renders a link (<a>) instead of a <button>. */
href?: string;
className?: string;
children: React.ReactNode;
disabled?: boolean;

dtsPropsFor.Accordion:
/** "single" = one panel open at a time; "multiple" = many. */
type: "single" | "multiple";
/** Allow closing the open item (type="single"). */
collapsible?: boolean;
/** Initially-open item value(s). */
defaultValue?: string | string[];
value?: string | string[];
onValueChange?: (value: string | string[]) => void;
className?: string;
children: React.ReactNode;

dtsPropsFor.AccordionItem:
/** Unique value identifying this panel. */
value: string;
disabled?: boolean;
className?: string;
children: React.ReactNode;

dtsPropsFor.ServiceCard:
/** Service content (from content/services). */
service: {
  id: string;
  name: string;
  icon: React.ComponentType<{ className?: string }>;
  summary: string;
  previewExamples: string[];
};
className?: string;

dtsPropsFor.TrustCard:
/** Headline statement. */
title: string;
/** Supporting text under the title. */
body: React.ReactNode;
/** Optional icon (lucide). Cards without an icon get a gold left-border. */
icon?: React.ComponentType<{ className?: string }>;
/** Optional numeric marker (e.g. "01") for numbered belief lists. */
marker?: string;
className?: string;

dtsPropsFor.FeatureGrid:
/** The cards to lay out. */
children: React.ReactNode;
/** Columns at the large breakpoint — defaults to 3. */
columns?: 2 | 3 | 4;
/** Stagger each child's reveal animation — defaults to true. */
stagger?: boolean;
className?: string;

dtsPropsFor.ProcessStep:
/** Step content (from content/process). */
step: {
  number: string;
  label: string;
  title: string;
  description: string;
  icon: React.ComponentType<{ className?: string }>;
};
/** Hides the connector line below the final step. */
isLast?: boolean;
/** Position, used to stagger the reveal. */
index?: number;

dtsPropsFor.PageHero:
/** Small kicker line above the title. */
eyebrow: string;
title: React.ReactNode;
description?: React.ReactNode;
/** Optional CTA row or extra content below the description. */
children?: React.ReactNode;
className?: string;

dtsPropsFor.SectionHeader:
eyebrow?: string;
title: React.ReactNode;
description?: React.ReactNode;
/** Text alignment — defaults to "left". */
align?: "left" | "center";
/** Heading level — defaults to "h2". */
as?: "h2" | "h3";
className?: string;
titleClassName?: string;

dtsPropsFor.CTASection:
/** All optional — default to the homepage CTA copy. */
eyebrow?: React.ReactNode;
title?: React.ReactNode;
body?: React.ReactNode;
supportText?: React.ReactNode;
/** Hide the secondary "Request a Demo" action. */
showSecondary?: boolean;

dtsPropsFor.LocalCallout:
/** Kicker line — defaults to "Local-first". */
eyebrow?: string;
title: React.ReactNode;
description?: React.ReactNode;
/** Bullet points shown as a checklist. */
points?: string[];
/** Extra content (e.g. a button) below the points. */
children?: React.ReactNode;
className?: string;

dtsPropsFor.Container:
/** Element/tag to render — defaults to "div". */
as?: React.ElementType;
/** Max content width — defaults to "default". */
size?: "default" | "narrow" | "wide";
className?: string;
children: React.ReactNode;

dtsPropsFor.Logo:
className?: string;
/** Light text for dark backgrounds — defaults to "dark". */
tone?: "dark" | "light";
/** Show the "Harborline Systems" wordmark — defaults to true. */
showWordmark?: boolean;

dtsPropsFor.Reveal:
children: React.ReactNode;
/** Stagger delay in seconds applied on reveal. */
delay?: number;
className?: string;
